  const prevImage = () => {
    const prevIdx = (currentIndex - 1 + filteredImages.length) % filteredImages.length;
    setSelectedImg(filteredImages[prevIdx]);
    setCurrentIndex(prevIdx);
  };

  return (
    <motion.div
