                      >
                        {loading ? "PROCESSING..." : "SUBMIT APPLICATION"} <Sparkles size={20} />
                      </button>
                    )}
                  </div>
                </form>
              </div>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

